/linkedin.com/in/ACoAAAaiywEB-ZgsoFWyGeEztEZgcUP0LCN7_lc", "peopleAlsoViewed/24/entity_urn": "urn:li:fsd_profile:ACoAABdP_zMBwNtBxl0pK8UrN8XjBwS2j_wORGg", "peopleAlsoViewed/24/first_name": "João", "peopleAlsoViewed/24/follower_count": "5249", "peopleAlsoViewed/24/headline": "Executive Chef | Anantara Lawana Koh Samui Resort ", "peopleAlsoViewed/24/last_name": "Costa", "peopleAlsoViewed/24/premium": "false", "peopleAlsoViewed/24/public_identifier": "joão-costa-983b99aa", "peopleAlsoViewed/24/url": "https://linkedin.com/in/ACoAABdP_zMBwNtBxl0pK8UrN8XjBwS2j_wORGg", "peopleAlsoViewed/25/entity_urn": "urn:li:fsd_profile:ACoAAADuSNwBij2tLVoFgEqKCJQYMlmR5hOHosk", "peopleAlsoViewed/25/first_name": "Christian", "peopleAlsoViewed/25/follower_count": "7506", "peopleAlsoViewed/25/headline": "Seasoned Luxury Hotel General Manager / Pre-Opening & Post-Opening / Rebranding experience ", "peopleAlsoViewed/25/last_name": "Gerart", "peopleAlsoViewed/25/premium": "true", "peopleAlsoViewed/25/profile_picture": "https://media.licdn.com/dms/image/v2/D5603AQHDgMeu8kTozw/profile-displayphoto-shrink_800_800/B56ZOVVv0QGcAc-/0/1733377343632?e=1778112000&v=beta&t=fMM27H1SIXeMkq96YJepF68MxdAscsv7psbzwhzd6dw", "peopleAlsoViewed/25/public_identifier": "christian-gerart-1b82915", "peopleAlsoViewed/25/url": "https://linkedin.com/in/ACoAAADuSNwBij2tLVoFgEqKCJQYMlmR5hOHosk", "publicIdentifier": "alexanderwillmann", "recommendations/0/context": "Alexander worked with Laura on the same team", "recommendations/0/date": "September 30, 2025", "recommendations/0/description": "I had the privilege of working closely with Laura during her tenure as PR & Marketing Manager at Anantara Lawana Koh Samui. She consistently demonstrated exceptional professionalism, creativity, and strategic foresight.\n\nLaura successfully led integrated marketing communications and brand positioning during a pivotal period of the resort’s rebranding and relaunch. Her ability to craft and execute 360° marketing strategies across accommodation, F&B, and wellness positioned the resort at the forefront of luxury hospitality in Koh Samui.\n\nHer leadership in campaign management, creative direction, and storytelling translated into powerful results: securing global PR coverage, orchestrating high-impact press campaigns such as The White Lotus feature, and driving international accolades including MICHELIN Guide, Condé Nast Traveller, and Elite Traveler recognition.\n\nBeyond her strong technical expertise in SEO, digital media, and content strategy, Laura excelled in fostering partnerships with leading publications, influencers, and KOLs, amplifying our brand presence worldwide.\n\nLaura is not only highly skilled but also collaborative, resilient, and visionary—a true asset to any organization seeking to elevate its brand reputation and market positioning. I recommend her wholeheartedly and without reservation.", "recommendations/0/name": "Laura Rand", "recommendations/0/subtitle": "PR & Marketing Manager", "recommendations/0/url": "https://www.linkedin.com/in/laura-rand-204a5050/", "recommendations/0/urn": "urn:li:fsd_profile:ACoAAArVTiQBRuBsL0qBKfKLq5bPeiV4_OZGYVs", "recommendations/1/context": "Alexander managed Erni directly", "recommendations/1/date": "April 5, 2020", "recommendations/1/description": "Erni is a young and motivated management professional whereby her capabilties go far beyond the customer services area. She is genuinely passionate about the day to day work including and not limited to client satisfaction and the overall team welfare. Erni has worked on different projects and implemented several rewarding initiatives within the department related to agent satisfaction and team motivation. She is well known as being friendly and professional in her approach and has a great motivation to build her skills towards business and product development. Erni has a great future ahead and it was a pleasure working with her at Asian Trails Indonesia. ", "recommendations/1/name": "Erni Cahriani", "recommendations/1/subtitle": "Available for New Opportunities", "recommendations/1/url": "https://www.linkedin.com/in/erni-cahriani/", "recommendations/1/urn": "urn:li:fsd_profile:ACoAABxYLPEBV-9BGWGZ3L5u4oiEq6OMFh83-So", "recommendations/2/context": "Alexander managed Maain directly", "recommendations/2/date": "February 24, 2020", "recommendations/2/description": "Maain is a very motivated management professional and leader and it was a pleasure working with him during his assignment as Duty Manager at Conrad Maldives Rangali Island. He is genuinely passionate about the day to day work including and not limited to guest and team welfare. Maain implemented several rewarding initiatives within the department in terms of customer satisfaction, upselling and team motivation. He goes above and beyond to personally ensure the wellbeing of properties guests and especially focuses on individual needs while building a close report and trust with everyone involved.  Maain has a great future ahead and soon will achieve his next goal in becoming an assistant/head of department.", "recommendations/2/name": "Maain Shahid", "recommendations/2/subtitle": "Front Office Manager at Fairmont Chateau Lake Louise", "recommendations/2/url": "https://www.linkedin.com/in/maain-shahid-78044b76/", "recommendations/2/urn": "urn:li:fsd_profile:ACoAABAVYpABVsp5VJxx2AsnQ0LlryoJfK5k3Y8", "recommendations/3/context": "Alexander worked with Prabu on the same team", "recommendations/3/date": "August 8, 2018", "recommendations/3/description": "It was a pleasure to work and collaborate with Prabu during his time at the Conrad Maldives Rangali Island as Food and Beverage Director. Prabu is genuinely passionate about his area of expertise and very innovative towards new promotions and developments to enhance the culinary art, revenue, guest- and team member experience. During our time at the resort Prabu has successfully implemented several new concepts in different bar and food locations which have been rewarded with high scores in terms of guest satisfaction and revenue. At the same time Prabu is one of the senior leaders who is personally ensuring the satisfaction of his guests and especially focuses on individual needs while building a close report with new guests as well as loyal and long-term repeaters. It has been my pleasure in working with Prabu and I wish him all the best for his future career, until we meet again. ", "recommendations/3/name": "Prabu Venugopal", "recommendations/3/subtitle": "Passionate Hotelier", "recommendations/3/url": "https://www.linkedin.com/in/prabu-venugopal-22274b19/", "recommendations/3/urn": "urn:li:fsd_profile:ACoAAAPY83oB0eFK-ApxkoMWqTr8fzdFtCElIZg", "recommendationsReceived/0/context": "Erni reported directly to Alexander", "recommendationsReceived/0/date": "November 14, 2023", "recommendationsReceived/0/description": "Working under Alex's guidance has been an incredibly rewarding experience. I admire his dedication to guest satisfaction and his commitment to maintaining high standards in every project. He's not just a great mentor for me but also has this talent for giving constructive feedback, providing insightful guidance, and inspiring team members to progress from good to better. Additionally, his friendly and approachable personality makes working with him a pleasure. Alex is always ready to help, and it has been truly enjoyable working with him.", "recommendationsReceived/0/name": "Erni Cahriani", "recommendationsReceived/0/subtitle": "Available for New Opportunities", "recommendationsReceived/0/url": "https://www.linkedin.com/in/erni-cahriani/", "recommendationsReceived/0/urn": "urn:li:fsd_profile:ACoAABxYLPEBV-9BGWGZ3L5u4oiEq6OMFh83-So", "recommendationsReceived/1/context": "Mahmoud reported directly to Alexander", "recommendationsReceived/1/date": "November 13, 2023", "recommendationsReceived/1/description": "Mr. Alex is not afraid to impart his expertise to the group. In addition to being a problem-solving leader, he also watches out for and mentors team members who have the ability to lead. He is the perfect example of the key principles that the company needs to uphold in order to accomplish its objectives, and our bond was so strong that we were able to work as a team to accomplish the goals. Meeting a leader who possesses such a strong sense of purpose and perseverance through difficult times is a rare opportunity. Working with him was an honor, and I won't hesitate to do so in the near future. He is an extremely great personality and resilience leader that you will definitely gain a lot of knowledge from him, and I personally had impaired the skillset on my work routine as well, I am \nincredibly grateful for the career advice he taught me.", "recommendationsReceived/1/name": "Mahmoud F.", "recommendationsReceived/1/subtitle": "Guest Experience Supervisor at Four Seasons | Surpassed 2024 Goals | Aspiring Guest Experience or Duty Manager | Passionate About Leadership & Luxury Hospitality", "recommendationsReceived/1/url": "https://www.linkedin.com/in/mahmoud-farhat/", "recommendationsReceived/1/urn": "urn:li:fsd_profile:ACoAAAqkWaMBPNc6Nv82tFqkHotgKCJExdwTdd8", "recommendationsReceived/2/context": "Axel was senior to Alexander but didn't manage Alexander directly", "recommendationsReceived/2/date": "February 1, 2013", "recommendationsReceived/2/description": "It was a pleasure to have Alexander as an energetic, motivated, friendly host on the team during our time at the Schloss Hotel Velden in Austria. He was in favor of our guests and liked throughout the hotel in the same time. A young service professional who will have a great career ahead of him. I would definitely work with him again in the future.", "recommendationsReceived/2/name": "Axel Bethke", "recommendationsReceived/2/subtitle": "General Manager Kempinski Hotel „Das Tirol“ Kitzbühel", "recommendationsReceived/2/url": "https://www.linkedin.com/in/axel-bethke-38817940/", "recommendationsReceived/2/urn": "urn:li:fsd_profile:ACoAAAiRQdgBO2UUJ4anMYcrIwgHc7Kudm-hEXA", "recommendationsReceived/3/context": "Tinashe was senior to Alexander but didn't manage Alexander directly", "recommendationsReceived/3/date": "January 29, 2013", "recommendationsReceived/3/description": "Alexander did an excellent job in this position as Supervisor Front Office and was an asset to our organization during his tenure with at Atlantis The Palm. He has excellent written and verbal communication skills, is extremely organized, can work independently, and is able to effectly multi-task to ensure that work is completed in a timely manner to ensure guest satisfaction.\n\nAlexander was always willing to offer his assistance and had an excellent rapport with guests and team members. He would be an asset to any employer and I recommend him for any endeavor he chooses to pursue.", "recommendationsReceived/3/name": "Tinashe Muvavarirwa", "recommendationsReceived/3/subtitle": "Hospitality Executive & Doctoral Researcher in AI Strategy Execution & Assimilation | AI | Architecting Business Models | Data Strategist | Leading Quality Systems (CQX) & Elevating Brand Experience", "recommendationsReceived/3/url": "https://www.linkedin.com/in/tinashe-muvavarirwa-56b3bab/", "recommendationsReceived/3/urn": "urn:li:fsd_profile:ACoAAAIEVaMBfnXbSAWN30-8R2z36jDB54YGgSA", "skills/0/title": "Resort Development", "skills/1/title": "Food and Beverage Operations", "skills/2/title": "Customer Support", "skills/3/title": "Customer Loyalty Management", "skills/4/title": "Build Strong Relationships", "skills/5/title": "Negotiation", "skills/6/title": "English", "skills/7/title": "Daily Reports", "skills/8/title": "Exceeding Customer Expectations", "skills/9/title": "Strategic Planning", "skills/10/title": "Multicultural Team Building", "skills/11/title": "Luxury", "skills/12/title": "Business Planning", "skills/13/title": "Corporate Financial Reporting", "skills/14/title": "Financial Performance", "skills/15/title": "Sales Strategy", "skills/16/title": "Public Speaking", "skills/17/title": "Team Leadership", "skills/18/title": "Coaching & Mentoring", "skills/19/title": "Project Management", "totalExperienceYears": "17.9", "totalRecommendationsGiven": "4", "totalRecommendationsReceived": "4", "updates/0/postLink": "https://www.linkedin.com/feed/update/urn:li:activity:7335246768944685057?updateEntityUrn=urn%3Ali%3Afs_feedUpdate%3A%28V2%2Curn%3Ali%3Aactivity%3A7335246768944685057%29", "updates/0/postText": "I am happy to share that I have started a new chapter as General Manager at Amari Koh Samui, part of ONYX Hospitality Group.\n\nIt is an honour to lead a property with such a strong legacy on this beautiful island—where heartfelt service, vibrant energy, and Thai warmth come together to create memorable guest experiences.\n\nLooking forward to working alongside a passionate team as we continue to elevate Amari Koh Samui's reputation as a leading destination in Thailand.\n\nHere is to new goals, new opportunities, and meaningful impact. Let’s make it unforgettable.\n\n#NewBeginnings #Leadership #Hospitality #AmariKohSamui #ONYXHospitality #ServiceWithHeart #GeneralManager #LuxuryTravel", "updates/0/type": "Post", "urn": "ACoAAAi8n1UBZDCyIs9Zd-uLWJpBKXYN1WYA_lk"}$$::jsonb),
